// main.js (public-facing worker)
import { fetch, Headers } from 'https://deno.land/x/dash@v0.9.0/mod.ts';
import { serve } from 'https://deno.land/std@0.135.0/http/server.ts';

async function forwardRequest(event) {
  const url = event.request.url; // Get the URL from the incoming request
  const response = await fetch(`${url}?worker=internal`, { headers: new Headers({ 'X-Forwarded-Url': url }) });
  return new Response(response.body, { status: response.status, headers: response.headers });
}

const server = serve((request) => {
  if (request.method === 'GET') {
    return forwardRequest(event);
  }
});

addEventListener('fetch', event => {
  event.respondWith(server(event));
});

